#include <bits/stdc++.h>
using namespace std;

const int N=2e6+10;

long long n,num[1010],p[N][4],s[N][4],ans;
int cnt[4],tot,d[4]={1,2,5,10};

long long phi(long long num){
    long long res=num;
    if(num%2==0) res/=2;
    if(num%5==0) res=res/5*4;
    return res;
}

int main(){
    scanf("%lld",&n);
    for(int tp=0;tp<4;tp++){
        long long m=n/d[tp];
        for(long long i=1,r;i<=m;i=r+1){
            r=m/(m/i);
            p[++cnt[tp]][tp]=r;
            s[cnt[tp]][tp]=s[cnt[tp]-1][tp]+1ll*(r-i+1)*(m/i);
        }
    }
    for(long long i=1;i<=n;i*=2)
        for(long long j=i;j<=n;j*=5)
            num[++tot]=j;
    sort(num+1,num+tot+1);
    for(int i=1,t[4]={1,1,1,1};i<=tot;i++){
        ans+=n/num[i]*phi(num[i]);
        for(int j=0;j<4;j++){
            while(t[j]<=cnt[j] && p[t[j]][j]<num[i]/d[j])
                t[j]++;
            if(num[i]%d[j]) continue;
            if(j==0 || j==3)
                ans+=s[cnt[j]][j]-s[t[j]][j]+(p[t[j]][j]-num[i]/d[j])*(n/num[i]);
            else
                ans-=s[cnt[j]][j]-s[t[j]][j]+(p[t[j]][j]-num[i]/d[j])*(n/num[i]);
        }
    }
    printf("%lld",ans);
    return 0;
}
